document.addEventListener("DOMContentLoaded",function(){var a=Array.prototype.slice.call(document.querySelectorAll(".navbar-burger"),0);a.length>0&&a.forEach(function(a){a.addEventListener("click",function(){var b=a.dataset.target,c=document.getElementById(b);a.classList.toggle("is-active"),c.classList.toggle("is-active")})})});function id(a){return document.getElementById(a)}function cl(a){return document.getElementsByClassName(a)}function body(){return document.getElementsByTagName("BODY")[0]}function setcookie(b,c,d){let a=new Date;a.setTime(a.getTime()+d*3600*1e3);let e="expires="+a.toUTCString();document.cookie=b+"="+c+"; "+e}function getcookie(e){let b=document.cookie,c=e+"=",a=b.indexOf("; "+c);if(a==-1){if(a=b.indexOf(c),a!=0)return null}else{a+=2;var d=document.cookie.indexOf(";",a);d==-1&&(d=b.length)}return unescape(b.substring(a+c.length,d))}function themeinit(){let a=getcookie('theme-mode');if(a=='light')body().setAttribute('data-theme','light');else if(a=='dark')body().setAttribute('data-theme','dark');else{let a=(new Date).getHours();a>=6&&a<18?body().setAttribute('data-theme','light'):body().setAttribute('data-theme','dark')}let b=id('mode-switch');b.addEventListener('click',b=>{let a=body().getAttribute('data-theme');a=='dark'&&(setcookie('theme-mode','light',12),body().setAttribute('data-theme','light'),body().classList.add('light')),a=='light'&&(setcookie('theme-mode','dark',12),body().setAttribute('data-theme','dark'),body().classList.add('dark'))})}themeinit();function headerhide(){var a=window.pageYOffset;window.onscroll=function(){var b=window.pageYOffset;a>b?id("header").style.top="0":id("header").style.top="-60px",a=b}}headerhide()